### 2️⃣ Cài đặt trong Python  

#### 2.1 Chuẩn bị môi trường
```bash
pip install python-dotenv   # nếu muốn lưu API key trong .env
```

#### 2.2 Định nghĩa lớp trợ giúp
```python
import json
import uuid
from datetime import datetime
from pathlib import Path

class ChatHistory:
    def __init__(self, file_path: str):
        self.file_path = Path(file_path)
        self.session = {
            "session_id": str(uuid.uuid4()),
            "started_at": datetime.utcnow().isoformat() + "Z",
            "messages": []
        }

        # Nếu file đã tồn tại → tải lên (để tiếp tục)
        if self.file_path.is_file():
            with self.file_path.open("r", encoding="utf-8") as f:
                self.session = json.load(f)

    def add_message(self, role: str, content: str):
        msg = {
            "id": f"msg-{len(self.session['messages']) + 1:03d}",
            "role": role,
            "content": content,
            "timestamp": datetime.utcnow().isoformat() + "Z"
        }
        self.session["messages"].append(msg)

    def save(self):
        # Ghi toàn bộ session vào file (overwrite)
        with self.file_path.open("w", encoding="utf-8") as f:
            json.dump(self.session, f, ensure_ascii=False, indent=2)

    def load(self):
        # Tải lại (nếu cần)
        with self.file_path.open("r", encoding="utf-8") as f:
            self.session = json.load(f)
```

#### 2.3 Sử dụng
```python
history = ChatHistory("chat_history.json")

# Khi người dùng gửi tin nhắn
history.add_message("user", "Xin chào bot!")

# Khi bot trả lời
history.add_message("assistant", "Chào bạn! Bạn muốn hỏi gì?")

# Lưu lại sau mỗi vòng trả lời
history.save()
```

> Lưu ý: `ensure_ascii=False` giúp giữ nguyên ký tự Unicode (tiếng Việt) trong file.

