### 3️⃣ Cài đặt trong Node.js (JavaScript)  

#### 3.1 Cài đặt gói cần thiết
```bash
npm init -y
npm install uuid
```

#### 3.2 Mã nguồn
```js
// chatHistory.js
const fs = require('fs');
const { v4: uuidv4 } = require('uuid');

class ChatHistory {
  constructor(filePath) {
    this.filePath = filePath;
    this.session = {
      session_id: uuidv4(),
      started_at: new Date().toISOString(),
      messages: []
    };

    // Load nếu file đã tồn tại
    if (fs.existsSync(this.filePath)) {
      const data = fs.readFileSync(this.filePath, 'utf-8');
      this.session = JSON.parse(data);
    }
  }

  addMessage(role, content) {
    const msg = {
      id: `msg-${String(this.session.messages.length + 1).padStart(3, '0')}`,
      role,
      content,
      timestamp: new Date().toISOString()
    };
    this.session.messages.push(msg);
  }

  save() {
    fs.writeFileSync(this.filePath, JSON.stringify(this.session, null, 2), 'utf-8');
  }

  load() {
    const data = fs.readFileSync(this.filePath, 'utf-8');
    this.session = JSON.parse(data);
  }
}

module.exports = ChatHistory;
```

#### 3.3 Sử dụng
```js
// app.js
const ChatHistory = require('./chatHistory');

const history = new ChatHistory('chat_history.json');

history.addMessage('user', 'Bạn khỏe không?');
history.addMessage('assistant', 'Mình khỏe, cảm ơn!');

history.save();   // Ghi vào file
```

